#!/usr/bin/env pwsh\n<#\n.SYNOPSIS\n    Local Windows Development Launcher for ICMS\n    \n.DESCRIPTION\n    Automates the complete setup for running ICMS locally on Windows.\n    Handles frontend build, environment validation, and backend startup.\n    \n.EXAMPLE\n    .\\start-local.ps1\n#>\n\nparam(\n    [switch]$SkipFrontend = $false,\n    [switch]$SkipMongo = $false,\n    [switch]$Debug = $false\n)\n\n# Colors for output\nfunction Write-Success([string]$Message) { Write-Host \"✅ $Message\" -ForegroundColor Green }\nfunction Write-Error-Custom([string]$Message) { Write-Host \"❌ $Message\" -ForegroundColor Red }\nfunction Write-Info([string]$Message) { Write-Host \"ℹ️  $Message\" -ForegroundColor Cyan }\nfunction Write-Warning-Custom([string]$Message) { Write-Host \"⚠️  $Message\" -ForegroundColor Yellow }\n\nWrite-Host \"\"\nWrite-Host \"========================================\" -ForegroundColor Magenta\nWrite-Host \"🚀 ICMS Local Windows Developer Setup\" -ForegroundColor Magenta\nWrite-Host \"========================================\" -ForegroundColor Magenta\nWrite-Host \"\"\n\n# ============ Validation Phase ============\n\nWrite-Info \"[1/5] Validating prerequisites...\"\n\n# Check Rust\nif (-not (Get-Command rustc -ErrorAction SilentlyContinue)) {\n    Write-Error-Custom \"Rust not found. Please install from https://rustup.rs/\"\n    exit 1\n}\nWrite-Success \"Rust installed: $(rustc --version)\"\n\n# Check Node.js\nif (-not (Get-Command node -ErrorAction SilentlyContinue)) {\n    Write-Error-Custom \"Node.js not found. Please install from https://nodejs.org/\"\n    exit 1\n}\nWrite-Success \"Node.js installed: $(node --version)\"\n\n# Check MongoDB\nif (-not $SkipMongo) {\n    if (-not (Get-Command mongosh -ErrorAction SilentlyContinue)) {\n        Write-Warning-Custom \"MongoDB Shell (mongosh) not found. MongoDB might still be running.\"\n        Write-Info \"    Install from: https://www.mongodb.com/try/download/community\"\n        Write-Info \"    Or start: net start MongoDB\"\n    } else {\n        Write-Success \"MongoDB Shell installed: $(mongosh --version)\"\n    }\n}\n\n# Check .env file\nif (-not (Test-Path \".env\")) {\n    Write-Error-Custom \".env file not found in project root\"\n    exit 1\n}\nWrite-Success \".env file found\"\n\nWrite-Host \"\"\n\n# ============ Frontend Build Phase ============\n\nif (-not $SkipFrontend) {\n    Write-Info \"[2/5] Building React frontend...\"\n    \n    if (-not (Test-Path \"frontend-TU\")) {\n        Write-Error-Custom \"frontend-TU directory not found\"\n        exit 1\n    }\n    \n    Push-Location frontend-TU\n    \n    Write-Info \"  Installing dependencies...\"\n    npm install --silent\n    \n    if ($LASTEXITCODE -ne 0) {\n        Write-Error-Custom \"npm install failed\"\n        Pop-Location\n        exit 1\n    }\n    \n    Write-Info \"  Building for production...\"\n    npm run build --silent\n    \n    if ($LASTEXITCODE -ne 0) {\n        Write-Error-Custom \"npm build failed\"\n        Pop-Location\n        exit 1\n    }\n    \n    if (Test-Path \"dist/index.html\") {\n        Write-Success \"Frontend built successfully\"\n    } else {\n        Write-Error-Custom \"dist/index.html not found after build\"\n        Pop-Location\n        exit 1\n    }\n    \n    Pop-Location\n    Write-Host \"\"\n} else {\n    Write-Info \"[2/5] Skipping frontend build (--SkipFrontend)\"\n}\n\n# ============ Environment Setup ============\n\nWrite-Info \"[3/5] Validating environment configuration...\"\n\n$env_content = Get-Content .env\n$mongodb_uri = $env_content | Select-String \"MONGODB_URI\" | Select-Object -First 1\n$rest_log = $env_content | Select-String \"RUST_LOG\" | Select-Object -First 1\n\nif ($mongodb_uri) {\n    Write-Success \"MONGODB_URI configured: $mongodb_uri\"\n} else {\n    Write-Error-Custom \"MONGODB_URI not found in .env\"\n    exit 1\n}\n\nif ($rest_log) {\n    Write-Success \"RUST_LOG configured: $rest_log\"\n}\n\nWrite-Host \"\"\n\n# ============ PostgreSQL Check ============\n\nWrite-Info \"[4/5] Checking MongoDB connectivity...\"\n\nif ($SkipMongo) {\n    Write-Warning-Custom \"MongoDB check skipped (--SkipMongo)\"\n} else {\n    # Try to connect to MongoDB\n    $mongo_url = \"mongodb://admin:admin123@localhost:27017/icms_db?authSource=admin\"\n    \n    try {\n        # Quick test - if mongosh exists\n        if (Get-Command mongosh -ErrorAction SilentlyContinue) {\n            $test = mongosh --eval \"db.adminCommand('ping')\" $mongo_url 2>&1 | Select-String \"ok\"\n            if ($test) {\n                Write-Success \"MongoDB is running and accessible\"\n            } else {\n                Write-Warning-Custom \"MongoDB might not be running or credentials are wrong\"\n                Write-Info \"    Start MongoDB: net start MongoDB\"\n                Write-Info \"    Or: mongod --dbpath 'C:\\data\\db'\"\n            }\n        }\n    } catch {\n        Write-Warning-Custom \"Could not verify MongoDB (mongosh not available)\"\n    }\n}\n\nWrite-Host \"\"\n\n# ============ Backend Startup ============\n\nWrite-Info \"[5/5] Starting Rust backend...\"\nWrite-Host \"\"\n\nPush-Location backend\n\nif ($Debug) {\n    Write-Info \"Starting with debug logging...\"\n    $env:RUST_LOG = \"debug\"\n} else {\n    $env:RUST_LOG = \"info\"\n}\n\nWrite-Info \"Launching: cargo run\"\nWrite-Info \"Press Ctrl+C to stop the server\"\nWrite-Host \"\"\nWrite-Host \"========================================\" -ForegroundColor Cyan\n\n# Run cargo\ncargo run\n\nif ($LASTEXITCODE -ne 0) {\n    Write-Error-Custom \"Backend startup failed\"\n    Pop-Location\n    exit 1\n}\n\nPop-Location\n